    // Optionally, add an event listener to automatically trigger the save after a delay
    setTimeout(simulateSaveButtonClick, 500); // Adjust delay as needed

    // Optionally, attach a click handler to a button to manually trigger the process
    const triggerButton = document.getElementById('trigger-save'); // Adjust selector as needed
    if (triggerButton) {
        triggerButton.addEventListener('click', () => {
            selectAllCheckboxes();
            simulateSaveButtonClick();
        });
    }
});
```

